const require_validation = require('./validation.cjs');
const require_findRubAlHizbByAyahId = require('./findRubAlHizbByAyahId.cjs');
const require_getRubAlHizb = require('./getRubAlHizb.cjs');

//#region src/getRubAlHizbByAyahId.ts
/**
* Finds the Juz, Hizb, and Rub-el-Hizb id for the given Ayah ID.
*
* @param ayahId - The Ayah ID to find the Juz, Hizb, and Hizb ID for.
* @param data - The Lists object for the riwaya.
* @returns An object containing the Juz, Hizb, and Hizb ID for the given Ayah ID.
*/
function getRubAlHizbByAyahId(ayahId, data) {
	require_validation.checkValidAyahId(ayahId, data.meta);
	return require_getRubAlHizb.getRubAlHizb(require_findRubAlHizbByAyahId.findRubAlHizbByAyahId(ayahId, data));
}

//#endregion
exports.getRubAlHizbByAyahId = getRubAlHizbByAyahId;